class Solution:
    def longestArithSeqLength(self, nums):
        # Brute force over every common difference d: standard 1D DP per d.
        best = 1
        diffs = set()
        for i in range(len(nums)):
            for j in range(i + 1, len(nums)):
                diffs.add(nums[j] - nums[i])
        for d in diffs:
            length = {}
            for v in nums:
                length[v] = length.get(v - d, 0) + 1
                if length[v] > best:
                    best = length[v]
        return best

