class Solution:
    def longestArithSeqLength(self, nums):
        n = len(nums)
        dp = [dict() for _ in range(n)]
        best = 1
        for j in range(n):
            for i in range(j):
                d = nums[j] - nums[i]
                dp[j][d] = dp[i].get(d, 1) + 1
                if dp[j][d] > best:
                    best = dp[j][d]
        return best

