var longestArithSeqLength = function(nums) {
    const n = nums.length;
    const dp = Array.from({ length: n }, () => new Map());
    let best = 1;
    for (let j = 0; j < n; j++) {
        for (let i = 0; i < j; i++) {
            const d = nums[j] - nums[i];
            const prev = dp[i].has(d) ? dp[i].get(d) : 1;
            dp[j].set(d, prev + 1);
            if (prev + 1 > best) best = prev + 1;
        }
    }
    return best;
};
